const mockGetRepository = jest.fn();
const mockQuery = jest.fn();

jest.mock('../../config/database', () => ({
  AppDataSource: {
    getRepository: (...args: unknown[]) => mockGetRepository(...args),
    query: (...args: unknown[]) => mockQuery(...args),
  },
}));

jest.mock('../../services/jobs/DistributedJobLockService', () => ({
  distributedJobLock: {
    withJobLock: jest.fn(async (_jobId: string, work: () => Promise<void>) => {
      await work();
      return { acquired: true, executed: true };
    }),
  },
}));

jest.mock('../../jobs/jobSchedulerHelper', () => ({
  scheduleDailyUtcJob: jest.fn(),
}));

jest.mock('../../utils/logger', () => ({
  logger: {
    info: jest.fn(),
    warn: jest.fn(),
    error: jest.fn(),
    debug: jest.fn(),
  },
}));

jest.mock('../../services/user/GdprDataDeletionService', () => ({
  getGdprDataDeletionService: jest.fn(() => ({
    processDueDeletions: jest.fn().mockResolvedValue([]),
  })),
}));

jest.mock('../../models/UserConsent', () => ({
  UserConsent: class UserConsent {},
}));

import { GdprDataCleanupJob } from '../../jobs/gdprDataCleanup';

interface GdprJobPrivate {
  cleanupAccessLogs(): Promise<number>;
  anonymizeUserActivities(): Promise<number>;
  cleanupExpiredConsents(): Promise<number>;
}

describe('GdprDataCleanupJob error propagation', () => {
  let job: GdprDataCleanupJob;

  beforeEach(() => {
    jest.clearAllMocks();
    job = new GdprDataCleanupJob();
  });

  it('should throw when cleanupAccessLogs query execution fails', async () => {
    const execute = jest.fn().mockRejectedValue(new Error('access-log-delete-failed'));
    const where = jest.fn(() => ({ execute }));
    const del = jest.fn(() => ({ where }));
    const createQueryBuilder = jest.fn(() => ({ delete: del }));

    mockGetRepository.mockReturnValue({ createQueryBuilder });

    await expect((job as unknown as GdprJobPrivate).cleanupAccessLogs()).rejects.toThrow(
      'access-log-delete-failed'
    );
  });

  it('should throw when anonymizeUserActivities batch query fails', async () => {
    const getRawMany = jest.fn().mockRejectedValue(new Error('activity-select-failed'));
    const limit = jest.fn(() => ({ getRawMany }));
    const orderBy = jest.fn(() => ({ limit }));
    const andWhere = jest.fn(() => ({ orderBy }));
    const where = jest.fn(() => ({ andWhere }));
    const select = jest.fn(() => ({ where }));
    const createQueryBuilder = jest.fn(() => ({ select }));

    mockGetRepository.mockReturnValue({ createQueryBuilder });

    await expect((job as unknown as GdprJobPrivate).anonymizeUserActivities()).rejects.toThrow(
      'activity-select-failed'
    );
  });

  it('should throw when cleanupExpiredConsents update execution fails', async () => {
    const execute = jest.fn().mockRejectedValue(new Error('consent-update-failed'));
    const andWhereSecond = jest.fn(() => ({ execute }));
    const andWhereFirst = jest.fn(() => ({ andWhere: andWhereSecond }));
    const where = jest.fn(() => ({ andWhere: andWhereFirst }));
    const set = jest.fn(() => ({ where }));
    const update = jest.fn(() => ({ set }));
    const createQueryBuilder = jest.fn(() => ({ update }));

    mockGetRepository.mockReturnValue({ createQueryBuilder });

    await expect((job as unknown as GdprJobPrivate).cleanupExpiredConsents()).rejects.toThrow(
      'consent-update-failed'
    );
  });
});
